INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '45467653-4374-46e5-b4eb-a6a4b6e00b44',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ — Why Queues Beat Direct Calls for Backend Workloads$escape$,
  $escape$When your API handler calls a downstream service synchronously, you inherit its latency, failure modes, and throughput limits. RabbitMQ breaks that coupling by placing an AMQP exchange between producer and consumer. The producer publishes to an exchange, routing keys determine which queues receive the message, and consumers pull independently — neither side knows the other exists at runtime.

This unlocks three concrete wins. First, decoupling: redeploy or scale your email service without touching your order API. Second, async processing: a POST /orders returns 202 immediately after publishing to the `orders.created` topic exchange; the fulfillment worker processes at its own pace. Third, load leveling: a queue with `x-max-length` or a classic mirrored queue absorbs traffic spikes that would otherwise cascade into 503s — consumers drain at a steady rate while RabbitMQ buffers the burst.

Prefetch count (`basic.qos`) is the knob that prevents a single consumer from being overwhelmed: set `prefetchCount: 1` to guarantee fair dispatch across worker instances, ensuring no consumer holds unacknowledged messages it can't process.$escape$,
  $escape$import amqp from 'amqplib';

const conn = await amqp.connect('amqp://localhost');
const ch = await conn.createChannel();

await ch.assertExchange('orders', 'topic', { durable: true });
await ch.assertQueue('orders.fulfillment', { durable: true });
await ch.bindQueue('orders.fulfillment', 'orders', 'orders.created');

// Producer: fire-and-forget, API returns immediately
ch.publish('orders', 'orders.created', Buffer.from(JSON.stringify({ orderId: 'abc123' })), { persistent: true });

// Consumer: process at controlled rate
await ch.prefetch(1);
ch.consume('orders.fulfillment', async (msg) => {
  if (!msg) return;
  await fulfillOrder(JSON.parse(msg.content.toString()));
  ch.ack(msg);
});$escape$,
