INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9823f2b2-9ba1-4ec1-8fa7-47d4a6b43e2a',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Dead Letter Queues — Poison Message Handling and Backoff Retry$escape$,
  $escape$When a message is rejected (basic.nack with requeue=false), exceeds its TTL, or hits a queue's x-max-length limit, RabbitMQ routes it to the Dead Letter Exchange (DLX) declared on that queue. The DLX then routes via normal exchange semantics to your dead letter queue (DLQ), preserving original headers plus x-death metadata — including the death count, reason, and source queue.

For retry-with-backoff, avoid a polling loop. Instead, create a series of per-delay queues (e.g. retry-5s, retry-30s, retry-2m), each with x-message-ttl and their own DLX pointing back to the primary exchange. On nack, set x-delay-level in a header and route to the appropriate retry queue. When TTL expires, RabbitMQ dead-letters the message back to the original queue automatically.

Poison message detection: read x-death[0].count from the headers. If count exceeds your threshold (e.g. 5), publish directly to a permanent DLQ and ack the message — never requeue it. Failing to ack poisons will cause infinite redelivery loops and block the channel's prefetch window.$escape$,
  $escape$// Node.js amqplib — declare queue with DLX and check x-death count
const channel = await connection.createChannel();

await channel.assertExchange('dlx', 'direct', { durable: true });
await channel.assertQueue('jobs.dlq', { durable: true });
await channel.bindQueue('jobs.dlq', 'dlx', 'jobs');

await channel.assertQueue('jobs', {
  durable: true,
  arguments: {
    'x-dead-letter-exchange': 'dlx',
    'x-dead-letter-routing-key': 'jobs',
  },
});

channel.consume('jobs', (msg) => {
  const deaths = msg.properties.headers['x-death'];
  const deathCount = deaths?.[0]?.count ?? 0;

  if (deathCount >= 5) {
    // Poison message — send to permanent graveyard and ack
    channel.publish('', 'jobs.graveyard', msg.content, { persistent: true });
    channel.ack(msg);
    return;
  }

  try {
    process(msg);
    channel.ack(msg);
  } catch {
    channel.nack(msg, false, false); // requeue=false → triggers DLX
  }
});$escape$,
  $escape$javascript$escape$,
