INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c4b5a735-88d4-4a03-bb1a-715047134cc4',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ — Exchanges, Routing Keys, Acks, and Prefetch Tuning$escape$,
  $escape$RabbitMQ never delivers messages directly to queues — producers publish to exchanges, which route via binding rules. A `direct` exchange matches exact routing keys; `topic` supports wildcards (`logs.#`, `order.*.created`); `fanout` ignores the key entirely and broadcasts to all bound queues.

Acknowledgements are where most production bugs hide. With `autoAck: false`, the broker holds the message unacked until your consumer calls `channel.ack(msg)`. Crash before acking? The message requeues. Call `channel.nack(msg, false, false)` to dead-letter it instead of looping forever.

Prefetch count (`channel.prefetch(n)`) is the lever for throughput vs. fairness. With `prefetch(1)`, a slow consumer won't starve the queue but limits parallelism. With `prefetch(50)`, a fast consumer batches more in-flight messages but risks losing 50 on crash if acks are deferred. Set per-channel, not per-connection — per-connection prefetch (`global: true`) applies across all consumers on that connection and is rarely what you want.$escape$,
  $escape$import amqplib from 'amqplib';

const conn = await amqplib.connect('amqp://localhost');
const ch = await conn.createChannel();

await ch.prefetch(10); // per-consumer, not global

await ch.assertExchange('orders', 'topic', { durable: true });
await ch.assertQueue('order.payments', { durable: true });
await ch.bindQueue('order.payments', 'orders', 'order.*.created');

ch.consume('order.payments', (msg) => {
  if (!msg) return;
  try {
    processOrder(JSON.parse(msg.content.toString()));
    ch.ack(msg);
  } catch {
    ch.nack(msg, false, false); // dead-letter, don't requeue
  }
}, { noAck: false });$escape$,
