INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0d18b980-3fa0-4b71-8b1d-dad1b96e86e1',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ + Redis Cache-Aside — Cutting DB Load in High-Throughput Consumers$escape$,
  $escape$When RabbitMQ consumers process thousands of messages per second, a DB round-trip per message kills throughput. Pair Redis as a cache layer using cache-aside: before hitting the DB, check Redis. On a miss, fetch from DB, write to Redis with `SETEX` (TTL-bounded), then process. Cache-aside is the right default for RabbitMQ consumer workers — they're read-heavy and lazy population fits the pull model naturally.

Write-through works when your producer controls data writes and needs read consistency, but adds latency to the publish path. Write-behind suits consumers that aggregate state (e.g. view counters) — buffer in Redis, flush to DB asynchronously via a separate worker or a second queue.

For RabbitMQ deduplication — critical when using `basic.deliver` with `redelivered=true` — use `SET msg:{message_id} 1 NX EX 60` before processing. If the key exists, ack and skip. This prevents double-processing without a DB write.

Eviction policy matters: `allkeys-lru` is safest for consumer caches where all keys are equally hot. Avoid `noeviction` under memory pressure — it will block Redis writes and stall your consumers.$escape$,
  $escape$import pika, redis, json

r = redis.Redis(host='localhost', decode_responses=True)

def on_message(ch, method, props, body):
    msg = json.loads(body)
    uid = msg['user_id']

    # Deduplication via Redis NX
    if not r.set(f"dedup:{props.message_id}", 1, nx=True, ex=60):
        ch.basic_ack(delivery_tag=method.delivery_tag)
        return

    user = r.get(f"user:{uid}")
    if not user:
        user = db.fetch_user(uid)
        r.setex(f"user:{uid}", 300, json.dumps(user))

    process(json.loads(user))
    ch.basic_ack(delivery_tag=method.delivery_tag)$escape$,
  $escape$python$escape$,
