INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2d7482ba-b596-4ec0-b1d1-fe4377ec878c',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Fanout Exchanges — Cache Invalidation Across Every Service Instance$escape$,
  $escape$Cache-aside keeps DB load low: on a miss, fetch from DB, write to Redis, serve from cache on subsequent hits. The vulnerability is invalidation — when data changes, stale entries silently serve wrong responses, and TTL-based expiry introduces jitter under write-heavy load. RabbitMQ's fanout exchange solves this precisely. On every DB write, publish a `cache.invalidate` message to the exchange. Each service instance declares an exclusive, auto-delete queue at startup and binds it to that exchange — AMQP guarantees every bound queue receives its own copy of the event. Crashed instances leave no orphaned queues; new instances auto-subscribe without config changes. For granular invalidation, swap to a topic exchange with routing key `cache.invalidate.user.{id}` so only the affected entity is evicted across all nodes, not the entire cache. `basic_ack` only after the local flush ensures no silent eviction failure. End result: cache-aside with strong consistency guarantees, DB reads reserved for true misses, latency sub-millisecond on cached paths.$escape$,
  $escape$import pika, json

connection = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
channel = connection.channel()

channel.exchange_declare(exchange='cache.invalidate', exchange_type='fanout')

result = channel.queue_declare(queue='', exclusive=True)  # auto-delete on disconnect
queue_name = result.method.queue
channel.queue_bind(exchange='cache.invalidate', queue=queue_name)

def on_invalidate(ch, method, properties, body):
    key = json.loads(body)['key']
    local_cache.delete(key)
    ch.basic_ack(method.delivery_tag)  # ack only after successful eviction

channel.basic_consume(queue_name, on_invalidate, auto_ack=False)
channel.start_consuming()$escape$,
  $escape$python$escape$,
