INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '72ff2ac2-71ba-4d1e-9495-b74a6ab749ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Backpressure — Taming Consumer Lag Before the Broker Runs Out of Memory$escape$,
  $escape$When consumers fall behind, RabbitMQ buffers undelivered messages in-memory per queue. Without constraints, a fast publisher can exhaust the broker's RAM, triggering the memory alarm (`vm_memory_high_watermark`, default 40% of system RAM). At that point RabbitMQ blocks all publishing connections via the `connection.blocked` AMQP mechanism — a hard, reactive stop instead of graceful backpressure.

The first line of defense is `basic.qos` with `prefetch_count`. Setting it to a small integer (e.g. 10) means the broker won't push more than 10 unacknowledged messages per channel. The consumer pulls the next batch only after acking the current one, naturally rate-limiting ingestion without any polling loop.

Pair that with queue-level overflow policy. Declare the queue with `x-max-length` and `x-overflow: reject-publish-dlx` to dead-letter excess messages rather than silently dropping them, giving you an audit trail.

For durable workloads, enable lazy queues (`x-queue-mode: lazy`) so messages are flushed to disk immediately, keeping the broker heap small regardless of queue depth. Monitor `rabbitmq_queue_messages_unacknowledged` in Prometheus — a rising unacked count is the earliest warning of a lagging consumer before memory pressure materializes.$escape$,
  $escape$import pika

conn = pika.BlockingConnection(pika.ConnectionParameters('localhost'))
ch = conn.channel()

# Declare a bounded, lazy queue with DLX overflow
ch.queue_declare(
    queue='jobs',
    durable=True,
    arguments={
        'x-max-length': 50_000,
        'x-overflow': 'reject-publish-dlx',
        'x-queue-mode': 'lazy',
        'x-dead-letter-exchange': 'jobs.dlx',
    },
)

# Pull at most 10 unacked messages per channel — core backpressure knob
ch.basic_qos(prefetch_count=10)

def on_message(ch, method, props, body):
    process(body)
    ch.basic_ack(method.delivery_tag)

ch.basic_consume('jobs', on_message)
ch.start_consuming()$escape$,
  $escape$python$escape$,
