INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd66e386e-4273-4be6-9336-0f68573e8a61',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ + Celery — Task Routing, Beat Scheduling, and Chaining Internals$escape$,
  $escape$Celery maps directly onto RabbitMQ's exchange/queue model. When you define `task_routes`, Celery binds each task to a named queue via the default direct exchange — workers started with `--queues gpu` only consume that queue, giving you hard workload isolation without extra brokers.

For result backends, never use `rpc://` in production. It spins up a per-task reply queue in RabbitMQ and never cleans them up reliably, flooding your vhost with thousands of ephemeral queues. Use `redis://` or `db+postgresql://` instead.

The beat scheduler is just a Celery producer that publishes tasks to RabbitMQ at the configured interval — pipe those through `task_routes` so periodic jobs don't compete with your hot path.

With `chain(a.s(), b.s(), c.s())`, each completed subtask publishes its return value to a RabbitMQ reply queue; the next task in the chain consumes it. If a step raises mid-chain, downstream tasks are silently abandoned. Protect against this with `task_acks_late=True` and a dead-letter exchange (`x-dead-letter-exchange`) on your queue — unacknowledged messages reroute there instead of disappearing.$escape$,
  $escape$from celery import Celery, chain

app = Celery("myapp", broker="amqp://guest:guest@localhost//", backend="redis://localhost/0")

app.conf.update(
    task_routes={
        "tasks.encode_video": {"queue": "gpu"},
        "tasks.send_email":   {"queue": "io"},
    },
    beat_schedule={
        "hourly-digest": {"task": "tasks.digest", "schedule": 3600.0, "options": {"queue": "io"}},
    },
    task_acks_late=True,
    task_reject_on_worker_lost=True,
)

# Each step publishes its result to a RabbitMQ reply queue consumed by the next task
pipeline = chain(download_asset.s(url), encode_video.s(), notify_user.s())
pipeline.delay()$escape$,
  $escape$python$escape$,
