INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fc68acc6-60c1-4006-b8de-190f7c4810a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ to NATS JetStream — Subject Routing and At-Least-Once Delivery Compared$escape$,
  $escape$RabbitMQ developers will find NATS JetStream's model familiar but flatter. Where RabbitMQ requires an exchange → binding → queue pipeline for topic routing, NATS subjects are first-class: `orders.created.us-east` routes natively via wildcard consumers (`orders.created.*`). No exchange declaration, no binding step.

JetStream replaces durable queues. A Stream captures published messages on a subject set; a Consumer defines delivery behavior. For at-least-once semantics — RabbitMQ's `basicAck`/`basicNack` equivalent — set `AckPolicy: AckExplicit`. Unacknowledged messages redeliver up to `MaxDeliver`. Unlike RabbitMQ's per-channel prefetch via `basic.qos`, JetStream throttles via `MaxAckPending` on the consumer config itself.

Dead-lettering maps loosely to `MaxDeliver` exhaustion: messages trigger advisories on `$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.>` rather than routing to an `x-dead-letter-exchange`. More manual than RabbitMQ's declarative DLX headers.

For throughput, prefer pull consumers — they batch-fetch like `basic.get` but with proper flow control. Push consumers resemble `basic.consume` but lack per-message backpressure, making them risky under load spikes RabbitMQ handles gracefully with prefetch count.$escape$,
  $escape$nc, _ := nats.Connect(nats.DefaultURL)
js, _ := nc.JetStream()

// RabbitMQ equiv: declare durable queue bound to topic exchange
js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
})

sub, _ := js.PullSubscribe("orders.created.*", "order-processor",
    nats.AckExplicit(),
    nats.MaxDeliver(5),
)

msgs, _ := sub.Fetch(10)
for _, msg := range msgs {
    process(msg)
    msg.Ack() // equiv: channel.basicAck(deliveryTag, false)
}$escape$,
  $escape$go$escape$,
