INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '120267eb-6f57-4b62-85c8-9db5f2216d05',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ — Matching BullMQ's Priorities, Rate Limits, Repeatable Jobs, and Dependencies$escape$,
  $escape$RabbitMQ supports priority queues natively via the `x-max-priority` queue argument (values 0–255). Declare the queue with that argument, then set `priority` in `sendToQueue` options — higher values are dequeued first within the same queue. For rate limiting, `channel.prefetch(n)` is your lever: it caps unacknowledged in-flight messages per consumer, throttling throughput at the protocol level without an external scheduler. Repeatable jobs require the `rabbitmq_delayed_message_exchange` plugin — declare an `x-delayed-message` exchange, publish with an `x-delay` header in milliseconds, and the broker holds the message until the delay elapses; re-publishing on consume simulates recurrence. For job dependencies, RabbitMQ has no native DAG support. You need a fan-in pattern: each completed job publishes to a coordination queue; a supervisor consumer decrements a counter (tracked in Redis or PostgreSQL) and only releases the dependent message when the count hits zero. Unlike BullMQ's `Job.addDependencies()`, this requires explicit orchestration. The tradeoff: RabbitMQ gives AMQP-level durability and routing flexibility; BullMQ gives richer scheduling primitives at the cost of Redis as a hard dependency.$escape$,
  $escape$import amqplib from 'amqplib';

const conn = await amqplib.connect('amqp://localhost');
const ch = await conn.createChannel();

// Priority queue: 0–10, higher value = dequeued first
await ch.assertQueue('jobs', { arguments: { 'x-max-priority': 10 } });

// Rate limiting: max 5 unacked messages in-flight per consumer
ch.prefetch(5);

// High-priority publish
ch.sendToQueue('jobs', Buffer.from(JSON.stringify({ task: 'critical' })), {
  priority: 9,
  persistent: true,
});

// Repeatable jobs via delayed exchange plugin
await ch.assertExchange('delayed', 'x-delayed-message', {
  arguments: { 'x-delayed-type': 'direct' },
});
ch.publish('delayed', 'jobs', Buffer.from(JSON.stringify({ task: 'poll' })), {
  headers: { 'x-delay': 30000 }, // re-publish inside consumer to repeat
});$escape$,
