INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f641ce75-89ee-4437-8307-627073157537',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Monitoring — Queue Depth, Consumer Lag, and DLQ Alerts That Actually Matter$escape$,
  $escape$RabbitMQ exposes three critical signals via its HTTP Management API that every production setup should alert on. Queue depth (`messages_ready`) reveals backpressure — if it climbs without consumers keeping pace, you're heading toward memory alarms or publisher blocks. Consumer lag is derived: divide `messages_ready` by `message_stats.deliver_get` rate to estimate drain time. No built-in metric exposes this directly, so poll `/api/queues/%2F/<queue>` and compute it yourself. Dead letter queues are your canary — a non-zero `messages_ready` on any `.dlq` or `.dead` suffixed queue means messages are failing silently. Wire all three into Prometheus via `rabbitmq_prometheus` plugin (enabled by default since 3.8). Key metrics: `rabbitmq_queue_messages_ready`, `rabbitmq_queue_messages_unacked`, and `rabbitmq_queue_messages` per queue. Set Alertmanager rules: fire if `messages_ready > 10000` for 5m, or if DLQ depth increases by any amount. Avoid alerting on `messages_unacked` alone — it spikes normally during processing bursts.$escape$,
  $escape$groups:
  - name: rabbitmq.rules
    rules:
      - alert: RabbitMQQueueDepthHigh
        expr: rabbitmq_queue_messages_ready{queue!~".*\.dlq"} > 10000
        for: 5m
        labels:
          severity: warning
        annotations:
          summary: "Queue {{ $labels.queue }} depth > 10k for 5m"

      - alert: RabbitMQDLQNonEmpty
        expr: rabbitmq_queue_messages_ready{queue=~".*\.dlq"} > 0
        for: 1m
        labels:
          severity: critical
        annotations:
          summary: "DLQ {{ $labels.queue }} has {{ $value }} unprocessed messages"$escape$,
  $escape$bash$escape$,
