INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e804885b-e878-428f-835b-be03a5ef130f',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Security — TLS, Certificate Auth, and vhost Isolation$escape$,
  $escape$RabbitMQ's default `guest` user is intentionally restricted to `localhost` — but production hardening goes further. Enable the `EXTERNAL` SASL mechanism to authenticate via x509 client certificates, mapping the cert's CN to a RabbitMQ username via `ssl_cert_login_from = common_name` in `rabbitmq.conf`. This eliminates password-based credentials entirely for service-to-service connections.

For TLS, set `listeners.ssl.default = 5671`, point `ssl_options.cacertfile`, `certfile`, and `keyfile` to your CA chain and broker cert, and enforce `ssl_options.verify = verify_peer` with `ssl_options.fail_if_no_peer_cert = true`. Disable SSLv3/TLSv1.0 via `ssl_options.versions.1 = tlsv1.3`.

Virtual hosts are RabbitMQ's primary isolation boundary — not just namespaces. Grant users per-vhost permissions with `rabbitmqctl set_permissions -p /payments svc-payments '.*' '.*' '.*'`, scoping configure/write/read separately. For network isolation, bind the AMQP listener to internal interfaces only (`listeners.tcp.default = 10.0.0.5:5672`) and expose the management plugin (`15672`) exclusively behind an internal load balancer or VPN.$escape$,
  $escape$import ssl
import pika

ssl_context = ssl.create_default_context(
    cafile="/etc/rabbitmq/ca_certificate.pem"
)
ssl_context.load_cert_chain(
    certfile="/etc/rabbitmq/client_cert.pem",
    keyfile="/etc/rabbitmq/client_key.pem"
)
ssl_context.verify_mode = ssl.CERT_REQUIRED

params = pika.ConnectionParameters(
    host="rabbitmq.internal",
    port=5671,
    virtual_host="/payments",
    credentials=pika.ExternalCredentials(),
    ssl_options=pika.SSLOptions(ssl_context, "rabbitmq.internal")
)
connection = pika.BlockingConnection(params)$escape$,
  $escape$python$escape$,
