INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd1adde72-874f-419b-a795-d1ba51f9375a',
  '00000000-0000-0000-0000-000000000001',
  $escape$RabbitMQ Horizontal Scaling — Competing Consumers, Prefetch, and Super Streams$escape$,
  $escape$RabbitMQ's competing consumers pattern scales horizontally by running N workers calling basic.consume on the same queue — the broker round-robins delivery automatically. The critical lever is basic.qos prefetch_count set at the channel level (global_qos=False). A prefetch of 1 gives perfect fairness but kills throughput; 10–50 is a practical range. Too high and a slow consumer hogs messages while others starve.

For ordered, partitioned scaling, RabbitMQ 3.11 introduced Super Streams — a special exchange backed by N stream partitions, each declared as a standard stream queue. Set x-single-active-consumer: true per partition and group consumers under a shared subscriber-name. When you scale up consumers, the broker automatically rebalances partition ownership, revoking and reassigning active-consumer leases. Offset tracking is per subscriber-name, so a rebalanced consumer resumes where its predecessor left off.

Choose the right model: quorum queues for unordered work queues where any consumer should pull any message; Super Streams when per-key ordering is required and you need Kafka-style partition affinity. Mixing both in one topology is valid — quorum for fire-and-forget jobs, Super Streams for ordered event pipelines.$escape$,
  $escape$import pika

params = pika.ConnectionParameters("localhost")
connection = pika.BlockingConnection(params)
channel = connection.channel()

channel.queue_declare(
    queue="orders",
    durable=True,
    arguments={"x-queue-type": "quorum"},
)
# Per-channel prefetch — each consumer holds at most 20 unacked messages
channel.basic_qos(prefetch_count=20, global_qos=False)
channel.basic_consume(queue="orders", on_message_callback=process_order, auto_ack=False)
channel.start_consuming()$escape$,
  $escape$python$escape$,
